import React, {useEffect, useState} from 'react';
import './App.scss';
import Button from './components/Button/Button';
import Viewer from './components/Viewer/Viewer';

const book = ['gallery/kadieva/01.jpg',
'gallery/kadieva/02.jpg',
'gallery/kadieva/03.jpg',
'gallery/kadieva/04.jpg',
'gallery/kadieva/05.jpg',
'gallery/kadieva/06.jpg',
'gallery/kadieva/07.jpg',
];

function App() {
  const value = { 
      scale: 0.5,
      translation: { x: 0, y: 0 }
  };

  const [img, setImg] = useState({src: book[0], key: 0});
  const [left, setLeft] = useState(true);
  const [right, setRight] = useState(false)

  const handleClickLeft = () => {
    if (img.key > 0) {
      let n = img.key - 1;
      setImg({src: book[n], key: n});
      setRight(false);
      // if (img.key < book.length - 1) {
      //   setRight(true);
      // }
    } else {
      setLeft(true)
    }
  }

  const handleClickRight = () => {
    if (img.key < book.length - 1) {
      let n = img.key + 1;
      setImg({src: book[n], key: n});
      setLeft(false);
    } else {
      setRight(true);
    }
  }

  return (
    <div className="App container">
      <Viewer value={value} src={img.src} />
      <div className="wrapper-flip">
        <Button onClick={handleClickLeft} className="btn-flip-left" disabled={left}>
          <svg width="13" height="21" viewBox="0 0 13 21" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M9.93934 20.5607C10.5251 21.1464 11.4749 21.1464 12.0607 20.5607C12.6464 19.9749 12.6464 19.0251 12.0607 18.4393L9.93934 20.5607ZM2 10.5L0.93934 9.43934C0.353553 10.0251 0.353553 10.9749 0.93934 11.5607L2 10.5ZM12.0607 2.56066C12.6464 1.97487 12.6464 1.02513 12.0607 0.43934C11.4749 -0.146447 10.5251 -0.146447 9.93934 0.43934L12.0607 2.56066ZM12.0607 18.4393L3.06066 9.43934L0.93934 11.5607L9.93934 20.5607L12.0607 18.4393ZM3.06066 11.5607L12.0607 2.56066L9.93934 0.43934L0.93934 9.43934L3.06066 11.5607Z"/>
          </svg>
        </Button>
        <Button onClick={handleClickRight} className="btn-flip-right" disabled={right}>
          <svg width="13" height="21" viewBox="0 0 13 21" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M3.06066 0.439339C2.47488 -0.146447 1.52513 -0.146447 0.939341 0.439339C0.353555 1.02513 0.353555 1.97487 0.939341 2.56066L3.06066 0.439339ZM11 10.5L12.0607 11.5607C12.6464 10.9749 12.6464 10.0251 12.0607 9.43934L11 10.5ZM0.93934 18.4393C0.353553 19.0251 0.353553 19.9749 0.93934 20.5607C1.52513 21.1464 2.47487 21.1464 3.06066 20.5607L0.93934 18.4393ZM0.939341 2.56066L9.93934 11.5607L12.0607 9.43934L3.06066 0.439339L0.939341 2.56066ZM9.93934 9.43934L0.93934 18.4393L3.06066 20.5607L12.0607 11.5607L9.93934 9.43934Z"/>
          </svg>
        </Button>
      </div>
    </div>
  );
}

export default App;
